bool is_monitoring_enabled(void) {
  return sv_currentSetPoint_queue_1 != NULL && sv_currentFanState_queue_1 != NULL && sv_latestTemp_queue_1 != NULL && sv_fanError_queue_1 != NULL;
}

void init(void) {
  printf("%s | INIT!\n", microkit_name);

  sb_queue_TempControl_SysVerif_Temperature_1_Recv_init(&currentTemp_recv_queue, (sb_queue_TempControl_SysVerif_Temperature_1_t *) currentTemp_queue_1);

  sb_queue_TempControl_SysVerif_FanCmd_1_init((sb_queue_TempControl_SysVerif_FanCmd_1_t *) fanCmd_queue_1);

  sb_queue_TempControl_SysVerif_SetPoint_1_init((sb_queue_TempControl_SysVerif_SetPoint_1_t *) sv_currentSetPoint_queue_1);

  sb_queue_TempControl_SysVerif_FanCmd_1_init((sb_queue_TempControl_SysVerif_FanCmd_1_t *) sv_currentFanState_queue_1);

  sb_queue_TempControl_SysVerif_Temperature_1_init((sb_queue_TempControl_SysVerif_Temperature_1_t *) sv_latestTemp_queue_1);

  sb_queue_bool_1_init((sb_queue_bool_1_t *) sv_fanError_queue_1);

  sb_queue_TempControl_SysVerif_SetPoint_1_Recv_init(&setPoint_recv_queue, (sb_queue_TempControl_SysVerif_SetPoint_1_t *) setPoint_queue_1);

  sb_queue_TempControl_SysVerif_FanAck_1_Recv_init(&fanAck_recv_queue, (sb_queue_TempControl_SysVerif_FanAck_1_t *) fanAck_queue_1);

  tcp_tct_initialize();

  microkit_notify(PORT_FROM_MON);
}

void notified(microkit_channel channel) {
  switch (channel) {
    case PORT_FROM_MON:
      tcp_tct_timeTriggered();
      break;
    default:
      tcp_tct_notify(channel);
  }
}
